solution_code:
#include <iostream>

template <int N>
void repeatChar(char c) {
    for (int i = 0; i < N; ++i)
        std::cout << c;
    std::cout << '\n';
}

int main() {
    char c;
    std::cin >> c;
    repeatChar<4>(c);
    repeatChar<7>(c);
    repeatChar<2>(c);
    return 0;
}

