#include <iostream>

template <int N>
int clampTo(int value) {
    if (value < -N) return -N;
    if (value > N)  return N;
    return value;
}

int main() {
    int v;
    std::cin >> v;
    std::cout << clampTo<50>(v) << '\n';
    return 0;
}
